fun solve(n: Long, k: Long): Long {
    if (k == 0L) {
        return 1
    }

    val depth = IntArray(61)
    depth[1] = 0
    for (i in 2..60) {
        val pop = i.countOneBits()
        depth[i] = 1 + depth[pop]
    }

    val setS = mutableSetOf<Int>()
    for (s in 1..50) {
        if (depth[s] == k.toInt() - 1) {
            setS.add(s)
        }
    }

    if (setS.isEmpty()) {
        return 0
    }

    val total = countNumbersWithPopcountInSet(n, setS)
    return if (k == 1L) total - 1 else total
}

private fun countNumbersWithPopcountInSet(n: Long, setS: Set<Int>): Long {
    val bin = n.toString(2)
    val len = bin.length
    val dp = Array(len + 1) { Array(len + 1) { LongArray(2) } }

    for (i in 0..len) {
        for (j in 0..len) {
            dp[i][j][0] = 0
            dp[i][j][1] = 0
        }
    }

    dp[0][0][1] = 1

    for (i in 0 until len) {
        for (count in 0..i) {
            for (tight in 0..1) {
                if (dp[i][count][tight] == 0L) continue

                val currentBit = bin[i] - '0'
                val upperBound = if (tight == 1) currentBit else 1

                for (choose in 0..upperBound) {
                    val newTight = if (tight == 1 && choose == upperBound) 1 else 0
                    val newCount = if (choose == 1) count + 1 else count
                    if (newCount <= len) {
                        dp[i + 1][newCount][newTight] += dp[i][count][tight]
                    }
                }
            }
        }
    }

    var total = 0L
    for (count in setS) {
        if (count <= len) {
            total += dp[len][count][0] + dp[len][count][1]
        }
    }
    return total
}
